  if (x < Lx && y < Ly) {
    int v00 = y*Lx + x;
    int v0p = y*Lx + (x + 1)%Lx;
    int v0m = y*Lx + (Lx + x - 1)%Lx;
    int vp0 = ((y+1)%Ly)*Lx + x;
    int vm0 = ((Ly+y-1)%Ly)*Lx + x;
    out[v00] = norm*in[v00] + delta*(in[v0p] + in[v0m] + in[vp0] + in[vm0]);
  }
}

void dev_lapl_iter(float *d_out, const float *d_in, const float delta, const float norm, const int Lx, const int Ly)
